/**
 * SkeletonKit — Enhanced skeleton loading components with shimmer animations
 *
 * Provides reusable loading skeletons that match the Aura Alpha design system.
 * Uses CSS @keyframes shimmer with linear-gradient sweep animation.
 *
 * Components:
 *   SkeletonTable      — configurable rows/columns, animated shimmer
 *   SkeletonCard       — card placeholder with image area + text lines
 *   SkeletonMetricRow  — row of 4-6 metric tiles
 *   SkeletonChart      — chart placeholder with axis lines
 *   SkeletonText       — paragraph-like text block
 */

const colors = {
  bg: '#0B0F14',
  surface: '#0F1620',
  surface2: '#111A24',
  border: '#1F2A37',
  shimmerBase: '#111A24',
  shimmerHighlight: '#1A2A3D',
  shimmerAccent: '#1B2D42',
};

const shimmerStyle = `
  @keyframes shimmer {
    0% { background-position: -200px 0; }
    100% { background-position: 200px 0; }
  }
`;

const baseShimmer = {
  animationName: 'shimmer',
  animationDuration: '1.8s',
  animationTimingFunction: 'linear',
  animationIterationCount: 'infinite',
  backgroundImage: `linear-gradient(90deg, ${colors.shimmerBase} 0%, ${colors.shimmerHighlight} 40%, ${colors.shimmerAccent} 50%, ${colors.shimmerHighlight} 60%, ${colors.shimmerBase} 100%)`,
  backgroundSize: '400px 100%',
  backgroundRepeat: 'no-repeat',
};

function ShimmerBar({ width = '100%', height = 14, delay = 0, borderRadius = 4, style = {} }) {
  return (
    <div
      style={{
        width,
        height,
        borderRadius,
        ...baseShimmer,
        animationDelay: `${delay}s`,
        ...style,
      }}
    />
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonTable — shimmer table with configurable rows/columns
   ════════════════════════════════════════════════════════════════ */
export function SkeletonTable({ rows = 5, columns = 4 }) {
  const cellWidths = ['60%', '80%', '50%', '70%', '45%', '55%', '65%', '40%', '75%', '35%'];
  return (
    <>
      <style>{shimmerStyle}</style>
      <div
        aria-busy="true"
        aria-label="Loading table data"
        style={{
          width: '100%',
          backgroundColor: colors.surface,
          border: `1px solid ${colors.border}`,
          borderRadius: 10,
          overflow: 'hidden',
        }}
      >
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              {Array.from({ length: columns }).map((_, i) => (
                <th
                  key={i}
                  style={{
                    padding: '10px 12px',
                    borderBottom: `1px solid ${colors.border}`,
                    backgroundColor: colors.surface,
                  }}
                >
                  <ShimmerBar width="70%" height={10} delay={i * 0.06} />
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {Array.from({ length: rows }).map((_, r) => (
              <tr key={r}>
                {Array.from({ length: columns }).map((_, c) => (
                  <td
                    key={c}
                    style={{
                      padding: '10px 12px',
                      borderBottom: r < rows - 1 ? `1px solid ${colors.border}` : 'none',
                    }}
                  >
                    <ShimmerBar
                      width={cellWidths[(r + c) % cellWidths.length]}
                      height={14}
                      delay={(r * columns + c) * 0.04}
                    />
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonCard — card placeholder with image area + text lines
   ════════════════════════════════════════════════════════════════ */
export function SkeletonCard({ width = '100%', height = 180, lines = 3 }) {
  return (
    <>
      <style>{shimmerStyle}</style>
      <div
        aria-busy="true"
        aria-label="Loading card"
        style={{
          width,
          minHeight: height,
          borderRadius: 14,
          backgroundColor: colors.surface,
          border: `1px solid ${colors.border}`,
          padding: 16,
          display: 'flex',
          flexDirection: 'column',
          gap: 12,
          boxSizing: 'border-box',
        }}
      >
        {/* Image/header area */}
        <ShimmerBar width="100%" height={height * 0.35} borderRadius={8} delay={0} />
        {/* Text lines */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {Array.from({ length: lines }).map((_, i) => {
            const w = i === lines - 1 ? `${55 + Math.floor(Math.random() * 25)}%` : `${80 + Math.floor(Math.random() * 20)}%`;
            return <ShimmerBar key={i} width={w} height={12} delay={0.1 + i * 0.08} />;
          })}
        </div>
        {/* Metric row at bottom */}
        <div style={{ display: 'flex', gap: 12, marginTop: 'auto' }}>
          <ShimmerBar width="25%" height={10} delay={0.3} />
          <ShimmerBar width="20%" height={10} delay={0.35} />
          <ShimmerBar width="22%" height={10} delay={0.4} />
        </div>
      </div>
    </>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonMetricRow — row of metric tiles
   ════════════════════════════════════════════════════════════════ */
export function SkeletonMetricRow({ count = 4 }) {
  const gap = 16;
  return (
    <>
      <style>{shimmerStyle}</style>
      <div
        aria-busy="true"
        aria-label="Loading metrics"
        style={{ display: 'flex', gap, width: '100%', flexWrap: 'wrap' }}
      >
        {Array.from({ length: count }).map((_, i) => (
          <div
            key={i}
            style={{
              flex: '1 1 0',
              minWidth: 120,
              backgroundColor: colors.surface,
              border: `1px solid ${colors.border}`,
              borderRadius: 10,
              padding: '14px 18px',
              display: 'flex',
              flexDirection: 'column',
              gap: 8,
            }}
          >
            <ShimmerBar width="55%" height={10} delay={i * 0.1} />
            <ShimmerBar width="40%" height={22} delay={i * 0.1 + 0.08} />
          </div>
        ))}
      </div>
    </>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonChart — chart placeholder with axis lines
   ════════════════════════════════════════════════════════════════ */
export function SkeletonChart({ height = 260 }) {
  return (
    <>
      <style>{shimmerStyle}</style>
      <div
        aria-busy="true"
        aria-label="Loading chart"
        style={{
          width: '100%',
          height,
          borderRadius: 10,
          backgroundColor: colors.surface,
          border: `1px solid ${colors.border}`,
          position: 'relative',
          overflow: 'hidden',
        }}
      >
        {/* Y-axis labels */}
        <div style={{ position: 'absolute', left: 12, top: 20, display: 'flex', flexDirection: 'column', gap: 32 }}>
          {Array.from({ length: 4 }).map((_, i) => (
            <ShimmerBar key={i} width={32} height={10} delay={i * 0.1} />
          ))}
        </div>

        {/* Y-axis grid lines */}
        {Array.from({ length: 4 }).map((_, i) => (
          <div
            key={`grid-${i}`}
            style={{
              position: 'absolute',
              left: 56,
              right: 16,
              top: 24 + i * 48,
              height: 1,
              background: `${colors.border}50`,
            }}
          />
        ))}

        {/* Faux chart waveform area */}
        <div
          style={{
            position: 'absolute',
            left: 56,
            right: 16,
            top: 20,
            bottom: 36,
            borderRadius: 6,
            ...baseShimmer,
            animationDelay: '0.15s',
            opacity: 0.6,
          }}
        />

        {/* X-axis labels */}
        <div style={{
          position: 'absolute',
          bottom: 10,
          left: 56,
          right: 16,
          display: 'flex',
          justifyContent: 'space-between',
        }}>
          {Array.from({ length: 6 }).map((_, i) => (
            <ShimmerBar key={i} width={32} height={8} delay={0.1 * i} />
          ))}
        </div>
      </div>
    </>
  );
}

/* ════════════════════════════════════════════════════════════════
   SkeletonText — paragraph-like text block
   ════════════════════════════════════════════════════════════════ */
export function SkeletonText({ lines = 3, width }) {
  const containerWidth = width || '100%';
  return (
    <>
      <style>{shimmerStyle}</style>
      <div
        aria-busy="true"
        aria-label="Loading text"
        style={{
          width: containerWidth,
          display: 'flex',
          flexDirection: 'column',
          gap: 8,
        }}
      >
        {Array.from({ length: lines }).map((_, i) => {
          const lineWidth = i === lines - 1
            ? `${55 + Math.floor(Math.random() * 30)}%`
            : '100%';
          return (
            <ShimmerBar
              key={i}
              width={lineWidth}
              height={14}
              delay={i * 0.08}
              borderRadius={6}
            />
          );
        })}
      </div>
    </>
  );
}

export default {
  SkeletonTable,
  SkeletonCard,
  SkeletonMetricRow,
  SkeletonChart,
  SkeletonText,
};
